{
  "query": "{ __schema { queryType { name } } }"
}

{
  "email": "doctor@example.com",
  "password": "password123"
}

{
  "query": "mutation CreateAppointment($appointment: AppointmentInput!) { createAppointment(appointment: $appointment) { id status description start end minutesDuration comment participant { status actor { reference display } required } } }",
  "variables": {
    "appointment": {
      "status": "PROPOSED",
      "description": "Regular checkup appointment",
      "start": "2024-12-15T10:00:00Z",
      "end": "2024-12-15T10:30:00Z",
      "minutesDuration": 30,
      "comment": "Patient requested morning appointment",
      "patientInstruction": "Please arrive 15 minutes early",
      "participant": [
        {
          "status": "ACCEPTED",
          "required": "REQUIRED",
          "actor": {
            "reference": "Patient/{{patient_id}}",
            "display": "John Doe"
          }
        },
        {
          "status": "ACCEPTED",
          "required": "REQUIRED",
          "actor": {
            "reference": "Practitioner/{{practitioner_id}}",
            "display": "Dr. Smith"
          }
        }
      ]
    }
  }
}

{
  "query": "query GetAppointment($id: ID!) { appointment(id: $id) { id resourceType status description start end minutesDuration comment patientInstruction participant { status actor { reference display } required } } }",
  "variables": {
    "id": "{{appointment_id}}"
  }
}

{
  "query": "query SearchAppointments($patientId: String) { appointments(patientId: $patientId) { id status description start end participant { actor { reference display } } } }",
  "variables": {
    "patientId": "{{patient_id}}"
  }
}

{
  "query": "query SearchAppointments($practitionerId: String) { appointments(practitionerId: $practitionerId) { id status description start end participant { actor { reference display } } } }",
  "variables": {
    "practitionerId": "{{practitioner_id}}"
  }
}

{
  "query": "query SearchAppointments($status: AppointmentStatus) { appointments(status: $status) { id status description start end participant { actor { reference display } } } }",
  "variables": {
    "status": "PROPOSED"
  }
}

{
  "query": "query SearchAppointments($date: String) { appointments(date: $date) { id status description start end participant { actor { reference display } } } }",
  "variables": {
    "date": "2024-12-15"
  }
}

{
  "query": "mutation UpdateAppointment($id: ID!, $appointment: AppointmentInput!) { updateAppointment(id: $id, appointment: $appointment) { id status description start end comment } }",
  "variables": {
    "id": "{{appointment_id}}",
    "appointment": {
      "status": "BOOKED",
      "description": "Updated regular checkup appointment",
      "start": "2024-12-15T10:00:00Z",
      "end": "2024-12-15T10:30:00Z",
      "minutesDuration": 30,
      "comment": "Appointment confirmed by patient"
    }
  }
}

{
  "query": "mutation CancelAppointment($id: ID!, $reason: String) { cancelAppointment(id: $id, reason: $reason) { id status comment } }",
  "variables": {
    "id": "{{appointment_id}}",
    "reason": "Patient requested cancellation"
  }
}

{
  "query": "mutation CreateSchedule($schedule: ScheduleInput!) { createSchedule(schedule: $schedule) { id resourceType active actor { reference display } comment } }",
  "variables": {
    "schedule": {
      "active": true,
      "actor": [
        {
          "reference": "Practitioner/{{practitioner_id}}",
          "display": "Dr. Smith"
        }
      ],
      "comment": "Regular clinic hours for Dr. Smith"
    }
  }
}

{
  "query": "query GetSchedule($id: ID!) { schedule(id: $id) { id resourceType active actor { reference display } comment } }",
  "variables": {
    "id": "{{schedule_id}}"
  }
}

{
  "query": "query SearchSchedules($actorId: String) { schedules(actorId: $actorId) { id active actor { reference display } comment } }",
  "variables": {
    "actorId": "{{practitioner_id}}"
  }
}

{
  "query": "query SearchSchedules($active: Boolean) { schedules(active: $active) { id active actor { reference display } comment } }",
  "variables": {
    "active": true
  }
}

{
  "query": "mutation CreateSlot($slot: SlotInput!) { createSlot(slot: $slot) { id resourceType status start end schedule { reference display } overbooked comment } }",
  "variables": {
    "slot": {
      "status": "FREE",
      "start": "2024-12-15T10:00:00Z",
      "end": "2024-12-15T10:30:00Z",
      "schedule": {
        "reference": "Schedule/{{schedule_id}}",
        "display": "Dr. Smith Schedule"
      },
      "overbooked": false,
      "comment": "Available 30-minute slot"
    }
  }
}

{
  "query": "query GetSlot($id: ID!) { slot(id: $id) { id resourceType status start end schedule { reference display } overbooked comment } }",
  "variables": {
    "id": "{{slot_id}}"
  }
}

{
  "query": "query SearchSlots($scheduleId: String) { slots(scheduleId: $scheduleId) { id status start end schedule { reference display } overbooked } }",
  "variables": {
    "scheduleId": "{{schedule_id}}"
  }
}

{
  "query": "query SearchSlots($status: SlotStatus) { slots(status: $status) { id status start end schedule { reference display } overbooked } }",
  "variables": {
    "status": "FREE"
  }
}

{
  "query": "query SearchSlots($start: String, $end: String) { slots(start: $start, end: $end) { id status start end schedule { reference display } } }",
  "variables": {
    "start": "2024-12-15T09:00:00Z",
    "end": "2024-12-15T17:00:00Z"
  }
}

{
  "query": "query PatientAppointments($id: ID!) { patient(id: $id) { id name { family given } appointments { id status description start end participant { actor { reference display } } } } }",
  "variables": {
    "id": "{{patient_id}}"
  }
}

{
  "query": "query UserAppointments($id: ID!) { user(id: $id) { id firstName lastName appointments { id status description start end participant { actor { reference display } } } } }",
  "variables": {
    "id": "{{practitioner_id}}"
  }
}

{
  "query": "query UserSchedules($id: ID!) { user(id: $id) { id firstName lastName schedules { id active actor { reference display } comment } } }",
  "variables": {
    "id": "{{practitioner_id}}"
  }
}

{
  "query": "mutation BookAppointmentFlow($appointment: AppointmentInput!) { createAppointment(appointment: $appointment) { id status description start end minutesDuration participant { status actor { reference display } required } } }",
  "variables": {
    "appointment": {
      "status": "BOOKED",
      "serviceCategory": [
        {
          "text": "General Medicine",
          "coding": [
            {
              "system": "http://terminology.hl7.org/CodeSystem/service-category",
              "code": "17",
              "display": "General Medicine"
            }
          ]
        }
      ],
      "serviceType": [
        {
          "text": "Consultation",
          "coding": [
            {
              "system": "http://terminology.hl7.org/CodeSystem/service-type",
              "code": "124",
              "display": "General Practice"
            }
          ]
        }
      ],
      "appointmentType": {
        "text": "Routine",
        "coding": [
          {
            "system": "http://terminology.hl7.org/CodeSystem/v2-0276",
            "code": "ROUTINE",
            "display": "Routine appointment"
          }
        ]
      },
      "reasonCode": [
        {
          "text": "Annual checkup",
          "coding": [
            {
              "system": "http://snomed.info/sct",
              "code": "185349003",
              "display": "Encounter for check up"
            }
          ]
        }
      ],
      "priority": 5,
      "description": "Annual health checkup with comprehensive examination",
      "start": "2024-12-20T14:00:00Z",
      "end": "2024-12-20T15:00:00Z",
      "minutesDuration": 60,
      "comment": "Patient has no known allergies. Last visit was 12 months ago.",
      "patientInstruction": "Please bring your insurance card and arrive 15 minutes early for check-in. Fasting is not required.",
      "participant": [
        {
          "type": [
            {
              "text": "Patient",
              "coding": [
                {
                  "system": "http://terminology.hl7.org/CodeSystem/v3-ParticipationType",
                  "code": "PPRF",
                  "display": "primary performer"
                }
              ]
            }
          ],
          "actor": {
            "reference": "Patient/{{patient_id}}",
            "display": "John Doe"
          },
          "required": "REQUIRED",
          "status": "ACCEPTED"
        },
        {
          "type": [
            {
              "text": "Practitioner",
              "coding": [
                {
                  "system": "http://terminology.hl7.org/CodeSystem/v3-ParticipationType",
                  "code": "PPRF",
                  "display": "primary performer"
                }
              ]
            }
          ],
          "actor": {
            "reference": "Practitioner/{{practitioner_id}}",
            "display": "Dr. Sarah Smith, MD"
          },
          "required": "REQUIRED",
          "status": "ACCEPTED"
        }
      ]
    }
  }
}

{
  "query": "mutation CreateWaitlistAppointment($appointment: AppointmentInput!) { createAppointment(appointment: $appointment) { id status description start end comment } }",
  "variables": {
    "appointment": {
      "status": "WAITLIST",
      "description": "Patient on waitlist for earlier appointment",
      "priority": 1,
      "comment": "Patient prefers morning appointments. Flexible with dates.",
      "patientInstruction": "We will contact you if an earlier slot becomes available",
      "participant": [
        {
          "actor": {
            "reference": "Patient/{{patient_id}}",
            "display": "John Doe"
          },
          "required": "REQUIRED",
          "status": "NEEDS_ACTION"
        }
      ]
    }
  }
}

{
  "query": "query CheckAvailability($practitionerId: String, $date: String) { appointments(practitionerId: $practitionerId, date: $date) { id status start end } slots(scheduleId: $practitionerId, start: $date) { id status start end overbooked } }",
  "variables": {
    "practitionerId": "{{practitioner_id}}",
    "date": "2024-12-20"
  }
}

{
  "query": "query GetAppointment($id: ID!) { appointment(id: $id) { id status } }",
  "variables": {
    "id": "non-existent-id"
  }
}

{
  "query": "mutation CreateAppointment($appointment: AppointmentInput!) { createAppointment(appointment: $appointment) { id status } }",
  "variables": {
    "appointment": {
      "status": "INVALID_STATUS",
      "start": "invalid-date",
      "end": "invalid-date"
    }
  }
}

{
  "query": "query BulkSearch { appointments { id status start end participant { actor { reference } } } schedules { id active actor { reference } } slots { id status start end } }"
}

{
  "query": "query ProviderUtilization($practitionerId: String, $date: String) { user(id: $practitionerId) { id firstName lastName appointments(date: $date) { id status start end } schedules { id active } } }",
  "variables": {
    "practitionerId": "{{practitioner_id}}",
    "date": "2024-12-20"
  }
}

{
  "query": "query FHIRValidation($id: ID!) { appointment(id: $id) { id resourceType identifier { use system value } status serviceCategory { text coding { system code display } } serviceType { text coding { system code display } } specialty { text coding { system code display } } appointmentType { text coding { system code display } } reasonCode { text coding { system code display } } priority description start end minutesDuration comment patientInstruction participant { type { text coding { system code display } } actor { reference display type } required status } } }",
  "variables": {
    "id": "{{appointment_id}}"
  }
}

{
  "query": "query FHIRScheduleValidation($id: ID!) { schedule(id: $id) { id resourceType identifier { use system value } active serviceCategory { text coding { system code display } } serviceType { text coding { system code display } } specialty { text coding { system code display } } actor { reference display type } comment } }",
  "variables": {
    "id": "{{schedule_id}}"
  }
}

{
  "query": "query FHIRSlotValidation($id: ID!) { slot(id: $id) { id resourceType identifier { use system value } serviceCategory { text coding { system code display } } serviceType { text coding { system code display } } specialty { text coding { system code display } } appointmentType { text coding { system code display } } schedule { reference display type } status start end overbooked comment } }",
  "variables": {
    "id": "{{slot_id}}"
  }
}
